import{_ as s,W as i,X as o,Z as e,$ as a,a0 as n,Y as p,C as d}from"./framework-b9c734bc.js";const t={},r=p('<h2 id="前言" tabindex="-1"><a class="header-anchor" href="#前言" aria-hidden="true">#</a> 前言</h2><p>使用Typora+PicGo+阿里云OSS+vuepress+GitHubPages可以让我们愉快的记录学习笔记，并且可随时随地的查看。</p><h2 id="配置阿里云oss" tabindex="-1"><a class="header-anchor" href="#配置阿里云oss" aria-hidden="true">#</a> 配置阿里云OSS</h2><p>在浏览器搜索阿里云OSS，即可找到官网；</p><h2 id="注册-开通对象储存" tabindex="-1"><a class="header-anchor" href="#注册-开通对象储存" aria-hidden="true">#</a> 注册,开通对象储存</h2><p>注册账户并实名后，右上角进入你的控制台；</p><div align="center"><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/vuepress/image-20230322161829574.png"></div><p>​ 选择对象储存并开通</p><div align="center"><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/vuepress/image-20230322162104741.png" alt="image-20230322162104741" style="zoom:50%;"></div><h2 id="创建bucket" tabindex="-1"><a class="header-anchor" href="#创建bucket" aria-hidden="true">#</a> 创建bucket</h2><p>在左侧选择概览，然后在右侧创建一个新的bucket。</p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/vuepress/image-20230322162152381.png" alt="创建Bucket列表" height="200;"><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/vuepress/image-20230322163210594.png" alt="创建注意点" style="zoom:40%;"><p>创建完成后，你的<code>bucket</code>就出现在了列表中</p><h2 id="找到你的地域节点" tabindex="-1"><a class="header-anchor" href="#找到你的地域节点" aria-hidden="true">#</a> 找到你的地域节点</h2><p>点击你的bucket名，然后点击bucket下的概览，在访问域名一栏找到你的地域节点，后面会用到。</p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/vuepress/image-20230322163903748.png" alt="image-20230322163903748" style="zoom:50%;"><p>如图，只需要复制<code>oss-cn-shenzhen</code>即可，不需要后面的<code>.aliyuncs.com</code></p><h2 id="找到你的key" tabindex="-1"><a class="header-anchor" href="#找到你的key" aria-hidden="true">#</a> 找到你的Key</h2><p>来到右上角，鼠标放在你的头像上，在弹出的框里选择AccessKey管理</p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/vuepress/image-20230322164217716.png" alt="image-20230322164217716" style="zoom:40%;"><p>在弹出的选项框里，选择“继续使用”</p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/git/image-20230322164314487.png" alt="image-20230322164314487" style="zoom:50%;"><p>进入后，创建一个AccessKey</p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/vuepress/image-20230322164418836.png" alt="image-20230322164418836" style="zoom:50%;"><p>在弹出的界面里，记住你的<code>accessKeyId</code>和<code>accessKeySecret</code>，也可以按提示下载到本地。</p><h2 id="给你的阿里云账户充值" tabindex="-1"><a class="header-anchor" href="#给你的阿里云账户充值" aria-hidden="true">#</a> 给你的阿里云账户充值</h2><h3 id="收费问题" tabindex="-1"><a class="header-anchor" href="#收费问题" aria-hidden="true">#</a> 收费问题</h3><p>阿里云OSS的各项收费是独立的！</p><p>对于图床而言，有两种收费形式。</p><p>以充值的方式使用储存容量以及流量(默认状态) 按年/月收费，购买一定存储包。流量额外收费 也就是说，即便你购买了下图的存储包，你依旧要为访问图床的流量付钱！</p><p>下图是在默认状态下，容量和流量收费的价格</p><p>图床使用的是标准型，请勿购买其他类型</p><p>储存容量：0.12元/GB/月 图片上传到阿里OSS流量：免费 外网流出流量(如typora访问图床图片)：闲时0.25元/GB，忙时0.50元/GB</p><p>仔细算算，我们图床的数据量其实很小的</p><p>0.12元/1GB/1个月，一年就是1.44元，远低于40GB的9元收费！</p><p>截图/照片以平均0.5mb/张估算，1gb可存放超过1600张图片！</p><p>数据低于6GB的情况下直接充值，以GB付费其实比购买储存包更加值得！</p><h3 id="注意事项" tabindex="-1"><a class="header-anchor" href="#注意事项" aria-hidden="true">#</a> 注意事项</h3><p>记得给阿里云账户充值！！别到时候欠费停用了！！ 刚开始作图床的时候，直接充值使用即可，无需购买容量包！</p><p>到这里，我们阿里云OSS基本配置完毕了😎</p><h2 id="配置picgo" tabindex="-1"><a class="header-anchor" href="#配置picgo" aria-hidden="true">#</a> 配置picgo</h2><p>打开picgo后，在你的状态栏里找到picgo的图标，打开picgo的主界面</p><h3 id="图床设置" tabindex="-1"><a class="header-anchor" href="#图床设置" aria-hidden="true">#</a> 图床设置</h3><p>在图床设置里面选择阿里云OSS，依照以下步骤填写信息</p><ol><li>设定<code>Keyld</code>：填写刚刚获得的<code>AccessKeyID</code></li><li>设定<code>KeySecret</code>：填写<code>AccessKeyIDSecret</code></li><li>设定储存空间名：填写<code>bucket</code>名称</li><li>这里填写的是<code>bucket</code>名称，不是浏览器里的域名</li><li>确认存储区域：填写你的地域节点，注意复制的格式</li><li>指定存储路径：其实就是自定义一个文件夹的名字，以/结尾</li><li>它会自动在你的<code>bucket</code>里面创建一个文件夹，并把图片上传进去</li></ol><p>弄完之后，记得“确定”，并点击“设置为默认图床”！</p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/vuepress/image-20230322164705726.png" alt="image-20230322164705726" style="zoom:50%;"><h3 id="picgo设置" tabindex="-1"><a class="header-anchor" href="#picgo设置" aria-hidden="true">#</a> picgo设置</h3><p>在设置里打开时间戳重命名和上传后自动复制URL</p><p>时间戳重命名：以上传时间来重命名图片，避免同名的图片无法上传（该设置不影响本地图片名）</p><h2 id="配置typora" tabindex="-1"><a class="header-anchor" href="#配置typora" aria-hidden="true">#</a> 配置typora</h2><p>进入typora主界面，点击左上角的“文件-偏好设置”</p><p>选择图像</p><p>插入图片时上传图片</p><p>下面的选项全勾上【更新22.03.05: 第二个网络位置的图片可以不勾，避免已经上传到图床的图片重复上传】</p><p>上传服务选择PicGo(app)</p><p>PicGo路径：找到picgo的安装路径 不是安装包的路径！！！！</p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/vuepress/image-20230322164942418.png" alt="image-20230322164942418" style="zoom:50%;"><p>5.大功告成！ 设置完毕后，我们点击验证图片上传选项</p><p>如果弹出以下弹窗，我们的图床就搞定了！😀</p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/vuepress/image-20230322165306009.png" alt="image-20230322165306009" style="zoom:50%;"><p>最后新建一个文件，验证图片是否正常上传</p><p>日常写作的时候，我们只需要复制图片，在typora里面粘贴即可，无需拖动！</p><p>我们的图床就大获全胜！</p><p>开始你的创作吧！🧐</p><h2 id="补充" tabindex="-1"><a class="header-anchor" href="#补充" aria-hidden="true">#</a> 补充</h2><p>虽然阿里云其外网流量的单价虽然不高，但如果被偷跑或攻击，再大的荷包也撑不住吧，因此我们可以设置相应的报警规则。</p>',68),h={href:"https://cloudmonitornext.console.aliyun.com/newOverview",target:"_blank",rel:"noopener noreferrer"},l=e("li",null,[e("p",null,"找到对象存储OSS；"),e("figure",null,[e("img",{src:"https://hk-docs.oss-cn-chengdu.aliyuncs.com/vuepress/image-20230322222506547.png",alt:"image-20230322222506547",tabindex:"0",loading:"lazy"}),e("figcaption",null,"image-20230322222506547")])],-1),u=e("li",null,[e("p",null,"然后根据自己的需求创建相应的报警规则。"),e("figure",null,[e("img",{src:"https://hk-docs.oss-cn-chengdu.aliyuncs.com/vuepress/image-20230322222655879.png",alt:"image-20230322222655879",tabindex:"0",loading:"lazy"}),e("figcaption",null,"image-20230322222655879")])],-1),g=e("p",null,"这样在我们的流量异常的时候，阿里云就会以短信、邮件等方式通知我们尽快处理，避免不必要的损失了。",-1);function m(y,b){const c=d("ExternalLinkIcon");return i(),o("div",null,[r,e("ol",null,[e("li",null,[e("p",null,[a("打开阿里云的"),e("a",h,[a("云监控控制台"),n(c)]),a("；")])]),l,u]),g])}const f=s(t,[["render",m],["__file","06.Aliyun-OSS-builds-a-picture-bed.html.vue"]]);export{f as default};
